<script setup>import {onMounted,reactive,ref} from 'vue';import {useRoute} from 'vue-router';import {getAdminTradeIn,updateAdminTradeIn} from '../api/tradeInApi';const route=useRoute(),item=ref(null),loading=ref(true),busy=ref(false),error=ref(''),success=ref(''),form=reactive({status:'INSPECTING',quotedPrice:null,rejectionReason:''});function sync(data){item.value=data;form.status=data.status;form.quotedPrice=data.quotedPrice;form.rejectionReason=data.rejectionReason||''}async function save(){busy.value=true;error.value='';success.value='';try{sync(await updateAdminTradeIn(item.value.id,form));success.value='收購狀態已更新。'}catch(e){error.value=e.message}finally{busy.value=false}}onMounted(async()=>{try{sync(await getAdminTradeIn(route.params.id))}catch(e){error.value=e.message}finally{loading.value=false}})</script>
<template><section class="admin-page"><RouterLink class="back-link" to="/admin/trade-ins">← 返回收購管理</RouterLink><p v-if="error" class="alert alert-error">{{error}}</p><p v-if="success" class="alert alert-success">{{success}}</p><div v-if="loading" class="loading-state">正在載入申請…</div><template v-else-if="item"><div class="page-heading"><div><span class="eyebrow">TRADE-IN REVIEW</span><h1>{{item.tradeInNumber}}</h1><p>{{item.memberName}} · {{item.brand}} {{item.model}}</p></div></div><div class="order-detail-grid"><section class="card detail-panel"><h2>檢測資料</h2><dl><dt>聯絡人</dt><dd>{{item.customerName}}／{{item.customerPhone}}</dd><dt>規格</dt><dd>{{item.storageCapacity||'-'}}／{{item.color||'-'}}</dd><dt>IMEI</dt><dd>{{item.imei||'-'}}</dd><dt>外觀</dt><dd>{{item.appearanceCondition}}</dd><dt>功能</dt><dd>{{item.functionCondition}}</dd><dt>說明</dt><dd>{{item.description||'無'}}</dd></dl></section><form class="card service-form" @submit.prevent="save"><h2>估價與狀態</h2><label>處理狀態<select v-model="form.status"><option v-for="v in ['SUBMITTED','INSPECTING','QUOTED','ACCEPTED','REJECTED','COMPLETED','CANCELLED']" :key="v">{{v}}</option></select></label><label>平台報價<input v-model.number="form.quotedPrice" type="number" min="0"></label><label>拒絕或處理說明<textarea v-model.trim="form.rejectionReason" rows="4"></textarea></label><button class="button button-primary" :disabled="busy">{{busy?'儲存中…':'儲存變更'}}</button></form></div></template></section></template>
